- (double)decimalYearWithJavaUtilGregorianCalendar:(JavaUtilGregorianCalendar *)cal {
  int32_t year = [((JavaUtilGregorianCalendar *) nil_chk(cal)) getWithInt:JavaUtilCalendar_YEAR];
  double daysInYear;
  if ([cal isLeapYearWithInt:year]) {
    daysInYear = 366.0;
  }
  else {
    daysInYear = 365.0;
  }
  return year + ([cal getWithInt:JavaUtilCalendar_DAY_OF_YEAR]) / daysInYear;
}

